class Solution {
    public int[] maxDepthAfterSplit(String seq) {
        int[] result = new int[seq.length()];
        int depthA = 0, depthB = 0;
        for (int i = 0; i < seq.length(); i++) {
            if (seq.charAt(i) == '(') {
                depthA++;
            } else if (seq.charAt(i) == ')') {
                depthA--;
            } else {
                depthB++;
            }
            result[i] = Math.max(depthA, depthB);
        }
        return result;
    }
}
```

